function parseIA(obj) {
    if (!obj) return null;

    if (typeof obj === 'object') {
        if (obj.pt || obj.en || obj.es) return obj;
        // Busca recursiva
        for (let key in obj) {
            if (['binary','data','headers'].includes(key)) continue;
            const res = parseIA(obj[key]);
            if (res) return res;
        }
        return null;
    }

    if (typeof obj === 'string') {
        try {
            let limpo = obj
                .replace(/```json/g, '')
                .replace(/```/g, '')
                .trim();
            const match = limpo.match(/\{[\s\S]*\}/);
            if (match) limpo = match[0];
            return JSON.parse(limpo);
        } catch (e) { return null; }
    }
    return null;
}

