function buscarTextoJson(obj) {
    if (!obj) return null;

    // 1. Se for string, verifica se parece nosso JSON (tem "pt" e "linkedin")
    if (typeof obj === 'string') {
        if (obj.includes('"pt"') && obj.includes('linkedin')) {
