    if (Array.isArray(obj)) {
        for (const item of obj) {
            const res = buscarTextoJson(item);
            if (res) return res;
        }
        return null;
    }

    // 3. Se for Objeto, varre as chaves
    if (typeof obj === 'object') {
        // Se já achou o objeto pronto
        if (obj.pt && obj.linkedin) return JSON.stringify(obj);

        const chaves = Object.keys(obj);
        for (const chave of chaves) {
            // Ignora a parte binária para ser rápido
            if (chave === 'binary' || chave === 'data') continue;

            const res = buscarTextoJson(obj[chave]);
            if (res) return res;
        }
    }
    return null;
}

